let p = msg.payload;
if (typeof p === 'string') {
  try { p = JSON.parse(p); } catch(e) { return null; }
}

let state = null;
if (p && p.current && p.current.state) state = p.current.state;
else if (p && p.state) state = p.state;
if (!state) return null;

let reported = state.reported || {};
let desired  = state.desired  || {};

let lock = (reported.lock || desired.lock || 'chiusa').toString();
flow.set('lock', lock);

// Forza stato iniziale = chiusa (solo la PRIMA volta)
if (!flow.get('initialized')) {
  flow.set('initialized', true);
  return [ null, { lockTarget: 'chiusa', reason: 'init' } ];
}

// Detect nuova request inviata dall'ESP (reported.request)
let req = reported.request;
if (req && req.nonce) {
  if (req.nonce !== flow.get('lastReqNonce')) {
    flow.set('lastReqNonce', req.nonce);
    return [ { payload: req }, null ];
  }
}

return null;

const CODE_OK = '0000';
const chatId = Number(env.get('chatid'));

let req = msg.payload || {};
let code  = (req.code  || '').toString();
let nonce = (req.nonce || '').toString();
let ts    = Number(req.ts || 0);
if (!ts || Number.isNaN(ts)) ts = Math.floor(Date.now() / 1000);

if (!nonce) return null;

let lock = (flow.get('lock') || 'chiusa').toString();

function nowIT() {
  try { return new Date().toLocaleString('it-IT', { timeZone: 'Europe/Rome' }); }
  catch (e) { return new Date().toLocaleString('it-IT'); }
}

function cleanupShadowNoChange(extra) {
  const out = { lockTarget: lock, reason: 'cleanup' };
  if (extra && Object.prototype.hasOwnProperty.call(extra, 'last_error')) {
    out.last_error = extra.last_error;
  }
  return out;
}

// Se c'è già una pending request, non sovrascrivere
let pending = flow.get('pending');
if (pending && pending.nonce && Date.now() < pending.expires) {
  return [
    {
      payload: {
        chatId,
        type: 'message',
        content: 'Richiesta già in corso: premi CONFERMA entro 10 secondi.'
      }
    },
    cleanupShadowNoChange({ last_error: null }),
    null
  ];
}

// CODICE ERRATO: Telegram + scrivi last_error + cleanup request
if (code !== CODE_OK) {
  const when = nowIT();
  return [
    {
      payload: {
        chatId,
        type: 'message',
        content: `🚫 Codice errato: accesso negato.\nOra: ${when}`
      }
    },
    cleanupShadowNoChange({
      last_error: { type: 'wrong_code', msg: 'Codice errato', nonce, ts }
    }),
    null
  ];
}

// CODICE CORRETTO

// Se è CHIUSA -> serve conferma Telegram entro 10s
if (lock === 'chiusa') {
  let expires = Date.now() + 10000;
  flow.set('pending', { nonce, expires });

  let oldTimer = flow.get('pendingTimer');
  if (oldTimer) {
    clearTimeout(oldTimer);
    flow.set('pendingTimer', null);
  }

  let t = setTimeout(() => {
    let p = flow.get('pending');
    if (p && p.nonce === nonce && Date.now() >= p.expires) {
      flow.set('pending', null);
      flow.set('pendingTimer', null);
      node.send([
        {
          payload: {
            chatId,
            type: 'message',
            content: 'Tempo scaduto: serratura NON aperta.'
          }
        },
        null,
        null
      ]);
    }
  }, 10000);
  flow.set('pendingTimer', t);

  // Pulisco request e cancello eventuali errori precedenti
  const cleanupMsg = cleanupShadowNoChange({ last_error: null });

  return [
    {
      // PASSO IL NONCE ANCHE NEL MSG per metriche
      _nonce: nonce,
      payload: {
        chatId,
        type: 'message',
        content: 'Codice corretto. Premi CONFERMA entro 10 secondi per APRIRE.',
        options: {
          reply_markup: JSON.stringify({
            inline_keyboard: [
              [ { text: 'CONFERMA', callback_data: 'CONFIRM|' + nonce } ]
            ]
          })
        }
      }
    },
    cleanupMsg,
    null
  ];
}

// Se è APERTA -> chiudi subito (senza Telegram)
return [
  {
    payload: {
      chatId,
      type: 'message',
      content: 'Codice corretto: chiusura automatica in corso.'
    }
  },
  { lockTarget: 'chiusa', reason: 'close', last_error: null },
  null
];

// Misura solo per il messaggio che contiene il bottone CONFERMA (link)
// Salva t0 su msg per poterlo leggere dopo il nodo Telegram Sender.

const p = msg.payload || {};
const opts = p.options || {};
const rm = (opts.reply_markup || '').toString();

// Se non c'è reply_markup, non è il link telegram
if (!rm) return msg;

// Estrai nonce dal callback_data: "CONFIRM|<nonce>"
let nonce = msg._nonce;
if (!nonce) {
  const m = rm.match(/CONFIRM\|([^"\s}]+)/);
  if (m && m[1]) nonce = m[1];
}

// Se non riesco ad estrarre nonce, non misuro
if (!nonce) return msg;

msg._metric = 'telegram_link_send';
msg._nonce = nonce;
msg._t0_ms = Date.now();
return msg;

let lockTarget = (msg.lockTarget || flow.get('lock') || 'chiusa').toString();

msg.payload = {
  state: {
    desired: {
      welcome: 'ESIT aws-iot',
      lock: lockTarget
    },
    reported: {
      welcome: 'ESIT aws-iot',
      lock: lockTarget,

      // pulizia campi inutili (rimozione con null)
      value: null,
      pending: null,
      reqid: null,
      req_ts: null,
      op: null,
      op_ts: null,
      action: null,
      request: null
    }
  }
};

// Scrive last_error SOLO se presente in msg (può essere anche null per cancellarlo)
if (Object.prototype.hasOwnProperty.call(msg, 'last_error')) {
  msg.payload.state.reported.last_error = msg.last_error;
}

return msg;

let lockTarget = (msg.lockTarget || (msg.payload && msg.payload.state && msg.payload.state.reported && msg.payload.state.reported.lock) || flow.get('lock') || 'chiusa').toString();

msg.topic = '$aws/things/esit-obj1/custom/lock_state';
msg.payload = lockTarget; // 'aperta' oppure 'chiusa'
return msg;

const chatId = Number(env.get('chatid'));
let pending = flow.get('pending');

let data = (msg.payload && msg.payload.content) ? msg.payload.content : null;

if (data && typeof data === 'object') {
  data = data.data || data.content || null;
}
if (!data && msg.originalMessage && msg.originalMessage.callback_query && msg.originalMessage.callback_query.data) {
  data = msg.originalMessage.callback_query.data;
}

if (!data || typeof data !== 'string') return null;
if (!data.startsWith('CONFIRM|')) return null;

let nonce = data.split('|')[1] || '';

if (!pending || !pending.nonce) {
  return [null, { payload: { chatId, type: 'message', content: 'Nessuna richiesta in corso.' } }];
}

if (nonce !== pending.nonce) {
  return [null, { payload: { chatId, type: 'message', content: 'Conferma non valida (nonce mismatch).' } }];
}

if (Date.now() > pending.expires) {
  flow.set('pending', null);
  let t = flow.get('pendingTimer');
  if (t) clearTimeout(t);
  flow.set('pendingTimer', null);

  return [null, { payload: { chatId, type: 'message', content: 'Tempo scaduto: serratura NON aperta.' } }];
}

flow.set('pending', null);
let t = flow.get('pendingTimer');
if (t) clearTimeout(t);
flow.set('pendingTimer', null);

return [
  { lockTarget: 'aperta', reason: 'open' },
  { payload: { chatId, type: 'message', content: 'Conferma ricevuta: serratura APERTA.' } }
];

// Calcola latency solo se proviene dal messaggio 'link' marcato prima del sender
if (msg._metric !== 'telegram_link_send' || !msg._t0_ms || !msg._nonce) return null;

const t1 = Date.now();
const latency = t1 - Number(msg._t0_ms);

msg.payload = {
  metric: 'telegram_link_send_latency_ms',
  nonce: msg._nonce,
  latency_ms: latency,
  t0_ms: msg._t0_ms,
  t1_ms: t1
};

return msg;
